const config = $input.first().json;
const enabled = Array.isArray(config.enabled_features) && config.enabled_features.includes('reviews');
return [{ json: { ...config, enabled } }];

const lead = $('When Called as Sub-workflow').first().json;
const config = $input.first().json;
return [{ json: { ...lead, ...config } }];

const d = $input.first().json;
return [{ json: {
  action: 'sign',
  client_slug: d.client_slug,
  source_type: d.source_type,
  source_ref: d.source_ref,
  secret: d.link_signing_secret
} }];

const { token, payload_b64 } = $input.first().json;
const d = $('Merge Lead and Config').first().json;

const base = 'https://flows.caiacdigital.com/webhook/review-rating';
const goodUrl = `${base}?t=${encodeURIComponent(token)}&p=${encodeURIComponent(payload_b64)}&r=good`;
const badUrl  = `${base}?t=${encodeURIComponent(token)}&p=${encodeURIComponent(payload_b64)}&r=bad`;

const subject = `How was your ${d.service} experience with ${d.client_name}?`;

const html = `<!DOCTYPE html>
<html>
<body style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px;color:#333;">
  <h2 style="color:#2c3e50;">How did we do?</h2>
  <p>Hi ${d.lead_name},</p>
  <p>Thank you for choosing <strong>${d.client_name}</strong> for your ${d.service}! We hope everything went smoothly.</p>
  <p>We'd love to hear about your experience:</p>
  <div style="text-align:center;margin:30px 0;">
    <a href="${goodUrl}" style="display:inline-block;background-color:#27ae60;color:white;padding:16px 32px;border-radius:8px;text-decoration:none;font-size:18px;margin:0 10px;">&#128077; Great Experience</a>
    &nbsp;&nbsp;
    <a href="${badUrl}" style="display:inline-block;background-color:#e74c3c;color:white;padding:16px 32px;border-radius:8px;text-decoration:none;font-size:18px;margin:0 10px;">&#128078; Could Be Better</a>
  </div>
  <p>If your experience was great, clicking the green button above takes you to Google where you can leave a review — it means the world to small businesses like <strong>${d.client_name}</strong>.</p>
  <hr style="border:none;border-top:1px solid #eee;margin:30px 0;">
  <p style="font-size:12px;color:#999;">This message was sent by CAIAC Digital's AI on behalf of ${d.client_name}. If you did not expect this email, please disregard it.</p>
</body>
</html>`;

return [{ json: {
  ...d,
  token,
  payload_b64,
  good_url: goodUrl,
  bad_url: badUrl,
  to: d.lead_email,
  from: 'no_reply@caiacdigital.com',
  subject,
  html
} }];

const d = $('Build Review Links and Email').first().json;
const isNew = d.lead_sheet_tab === 'Leads';
const fields = isNew
  ? { 'Lead Name': d.lead_name || '', 'Review Sent': 'TRUE' }
  : {
      'Source Ref':       d.source_ref,
      'Lead Name':        d.lead_name || '',
      'Service':          d.service || '',
      'Business Name':    d.business_name || '',
      'Address':          d.address || '',
      'Review Email Sent': 'TRUE'
    };
return [{ json: {
  source_type:    d.source_type,
  source_ref:     d.source_ref,
  lead_sheet_id:  d.lead_sheet_id,
  lead_sheet_tab: d.lead_sheet_tab,
  fields
} }];
